import React from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";

import LoginPage from "./pages/LoginPage";
import RegisterPage from "./pages/RegisterPage";

// Baaki pages baad me connect karenge
const DummyPage = ({ title }) => (
  <div style={{ padding: "40px", fontSize: "28px", fontWeight: "700" }}>
    {title}
  </div>
);

function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<LoginPage />} />
        <Route path="/register" element={<RegisterPage />} />

        <Route path="/dashboard" element={<DummyPage title="Admin Dashboard" />} />
        <Route path="/predict" element={<DummyPage title="Prediction Page" />} />
      </Routes>
    </Router>
  );
}

export default App;
